INT32 UIFlowWndWiFiMovie_OnOpen(VControl *pCtrl, UINT32 paramNum, UINT32 *paramArray)
{
	//printf("call UIFlowWndWiFiMovie_OnOpen\r\n");
    //after enter link wnd ,set wifi sub mode,avoid wifi on change normal movie mode
    System_ChangeSubMode(SYS_SUBMODE_WIFI);

    Ux_FlushEventByRange(NVTEVT_KEY_EVT_START, NVTEVT_KEY_EVT_END);
    /* Init window key mask variables & set key and key released mask */
    Input_SetKeyMask(KEY_PRESS, FLGKEY_KEY_MASK_DEFAULT);
    Input_SetKeyMask(KEY_RELEASE, FLGKEY_KEY_MASK_DEFAULT);
    Input_SetKeyMask(KEY_CONTINUE, FLGKEY_KEY_MASK_DEFAULT);
	Control_LedTurn(REC_LED,1);
	Check_LEDStatus();
    #if 1//(defined(_NVT_ETHREARCAM_RX_))
    g_bWiFiSlowCard = FALSE;
    //GxLED_SetCtrl(KEYSCAN_LED_FCS, TURNON_LED, TRUE);
    UIFlowWndWiFiMovie_Initparam();
    #endif
	if (UI_GetData(FL_ADAS_PANEL) == ADAS_PANEL_OFF) {
		UxCtrl_SetShow(&UIFlowWndWiFiMovie_Panel_Normal_DisplayCtrl, TRUE);
    	UxCtrl_SetShow(&UIFlowWndWiFiMovie_ADAS_Alert_DisplayCtrl, FALSE); 	
		UxCtrl_SetShow(&UIFlowWndWiFiMovie_ADAS_Alert_PanelCtrl, FALSE); 
	}
    
	FlowWiFiMovie_initIcon();

    FlowMovie_SetSOSStatusNow(FALSE);
    if (!bWndWiFiMovieOpenFirst)
    {
        //bWndWiFiMovieOpenFirst = TRUE;
        FlowWiFiMovie_IconDrawWiFiConnected(FALSE);
        UIFlowWndWiFiMovie_UpdateWiFiData(TRUE);
    }
    else
    {
        FlowWiFiMovie_IconDrawWiFiConnected(bWiFiConnected);
        UIFlowWndWiFiMovie_UpdateWiFiData(FALSE);
    }
    FlowWiFiMovie_UpdateIcons(TRUE);
	
#if (ACC_CLOSE_WIFI == ENABLE)
    if (ComingParkMode ||ExitParkMode) {	
	ComingParkMode = FALSE;
	ExitParkMode = FALSE;	
	Ux_PostEvent(NVTEVT_WIFI_EXE_MOVIE_REC, 1, 1);
    }
#endif

    if (WiFiCmd_GetStatus() == WIFI_MOV_ST_RECORD) {
        KeyScan_EnableMisc(FALSE);
    } else {
        KeyScan_EnableMisc(TRUE);
        if (!bWndWiFiMovieOpenFirst) {	
            	//Ux_PostEvent(NVTEVT_WIFI_EXE_MOVIE_REC, 1, 1);
            bWiFiModeChanged = TRUE;
        }
    }

	#if 1//GPS_PANEL_FUNC
	if (UI_GetData(FL_ADAS_PANEL) == ADAS_PANEL_ON) {
		UxCtrl_SetShow(&UIFlowWndWiFiMovie_Panel_Normal_DisplayCtrl, FALSE);		
		UxCtrl_SetShow(&UIFlowWndWiFiMovie_ADAS_Alert_DisplayCtrl, FALSE);	
		UxCtrl_SetShow(&UIFlowWndWiFiMovie_ADAS_Alert_PanelCtrl, TRUE);
		UI_SetData(FL_DUAL_CAM, DUALCAM_BEHIND);
		UI_SetData(FL_DUAL_CAM_MENU, UI_GetData(FL_DUAL_CAM));
		g_bSpeedPanelInit = TRUE;
	}
	#endif

    bWiFiRec_AutoStart = FALSE;
    bWiFiRec_AutoStop = FALSE;
	Set_IsRearOK(0);
    // Enable Motion Detect function in starting up movie mode
    if ((SysGetFlag(FL_MOVIE_MOTION_DET) == MOVIE_MOTIONDET_ON)&&(System_GetState(SYS_STATE_CARD) == CARD_INSERTED)) {
        g_uiWiFiRecordIngMotionDet = TRUE;
    } else {
        g_uiWiFiRecordIngMotionDet = FALSE;
    }

	if ((SysGetFlag(FL_PARKING_MODE) == PARKING_MODE_MOTION_DET)&&(System_GetState(SYS_STATE_CARD) == CARD_INSERTED)) {
		g_uiWiFiParkingModeMotionDet = TRUE;
	} else {
		g_uiWiFiParkingModeMotionDet = FALSE;
	}

    if (gUIFlowWndWiFiMotionDetTimerID == NULL_TIMER) {
		//printf("call gUIFlowWndWiFiMotionDetTimerID!\r\n");
        gUIFlowWndWiFiMotionDetTimerID = GxTimer_StartTimer(TIMER_HALF_SEC, NVTEVT_05SEC_TIMER, CONTINUE);
    }

    if (g_uiDateTimerID == NULL_TIMER) {
		//printf("call g_uiDateTimerID!\r\n");
        g_uiDateTimerID = GxTimer_StartTimer(TIMER_ONE_SEC, NVTEVT_1SEC_TIMER, CONTINUE);
    }

    #if 1//(defined(_NVT_ETHREARCAM_RX_))
    if (g_uiBeepTimerID == NULL_TIMER) {
		//printf("call g_uiBeepTimerID!\r\n");
        g_uiBeepTimerID = GxTimer_StartTimer(100, NVTEVT_01SEC_TIMER, CONTINUE);
    }
    #endif


    if (!bWndWiFiMovieOpenFirst) {
        //Ux_OpenWindow(&UIFlowWndWrnMsgCtrl, 2, FLOWWRNMSG_ISSUE_WIFI_CONTROL_TIP, FLOWWRNMSG_TIMER_3SEC);
    }
    bWndWiFiMovieOpenFirst = TRUE;
	WifiStarting = FALSE;
    Display_SetEnable(LAYER_VDO1, TRUE);
    FlowMovie_WakeUpLCDBacklight();
// test wifi need shield
#if (ASR_FUNCTION == ENABLE)

	if(System_GetState(SYS_STATE_NEXTMODE) != PRIMARY_MODE_PLAYBACK) {
		Dx_SetASR_Flag(0);
		ASR_GetPCMData_EN = FALSE;	 
		//wifi mode open ASR
		if (SysGetFlag(FL_ASR) == ASR_STANDARD) {
			ASR_SetMode(SysGetFlag(FL_LANGUAGE));
			ASR_Open();
		}
	}else{
		if (SysGetFlag(FL_ASR) == ASR_STANDARD) {
			//printf("call ASR_STANDARD \r\n",SysGetFlag(FL_ASR) );
			ASR_Uninstall();
			ASR_GetPCMData_EN = FALSE;	 
		}
	}
#endif
	beepCntTimeout =  0;
    Ux_DefaultEvent(pCtrl,NVTEVT_OPEN_WINDOW,paramNum,paramArray);
    return NVTEVT_CONSUME;
}
INT32 UIFlowWndWiFiMovie_OnClose(VControl *pCtrl, UINT32 paramNum, UINT32 *paramArray)
{
	//printf("call UIFlowWndWiFiMovie_OnClose\r\n");
    if (WiFiCmd_GetStatus() == WIFI_MOV_ST_RECORD) {
        if (FlowWiFiMovie_GetRecCurrTime() <= 1) {
            Delay_DelayMs(1000);
        }
        FlowWiFiMovie_StopRec();
        Delay_DelayMs(100);
    }

    if (gUIFlowWndWiFiMotionDetTimerID != NULL_TIMER) {
        GxTimer_StopTimer(&gUIFlowWndWiFiMotionDetTimerID);
    }

    if (g_uiDateTimerID != NULL_TIMER) {
        GxTimer_StopTimer(&g_uiDateTimerID);
    }

    #if 1//(defined(_NVT_ETHREARCAM_RX_))
    if (g_uiBeepTimerID != NULL_TIMER) {
		//printf("call GxTimer_StopTimer\r\n");
        GxTimer_StopTimer(&g_uiBeepTimerID);
    }
    #endif
    //LED_TurnOffLED(GPIOMAP_LED_WIFI);
    Ux_DefaultEvent(pCtrl,NVTEVT_CLOSE_WINDOW,paramNum,paramArray);
    return NVTEVT_CONSUME;
}
INT32 UIFlowWndWiFiMovie_OnChildClose(VControl *pCtrl, UINT32 paramNum, UINT32 *paramArray)
{
    Ux_DefaultEvent(pCtrl,NVTEVT_CHILD_CLOSE,paramNum,paramArray);
    return NVTEVT_CONSUME;
}
INT32 UIFlowWndWiFiMovie_OnKeyMenu(VControl *pCtrl, UINT32 paramNum, UINT32 *paramArray)
{
#if 1//(defined(_NVT_ETHREARCAM_RX_))
    UINT32  uiKeyAct;
    static  BOOL bMenuKeyPressed = FALSE;

    uiKeyAct = paramArray[0];

    switch (uiKeyAct) {
    case NVTEVT_KEY_PRESS:
        bMenuKeyPressed = TRUE;
        break;

    case NVTEVT_KEY_RELEASE:
        if (!bMenuKeyPressed) {
            break;
        }
        bMenuKeyPressed = FALSE;

        if (FlowMovie_WakeUpLCDBacklight()) {
            return NVTEVT_CONSUME;
        }

        if (System_GetState(SYS_STATE_CURRMODE) != PRIMARY_MODE_MOVIE) {
            return NVTEVT_CONSUME;
        }

        if ((System_GetState(SYS_STATE_CARD) == CARD_INSERTED) && (WiFiCmd_GetStatus() == WIFI_MOV_ST_RECORD)) {
            FlowWiFiMovie_DrawPIM(TRUE);
	   		Delay_DelayMs(100);
            Ux_SendEvent(&CustomMovieObjCtrl, NVTEVT_EXE_MOVIE_REC_RAWENC, 0);
			#if PLAY_SOUND_IN_OTHER_TASK
            UIDogSound_Enable(FALSE);
	        DogSoundPlayID(DEMOSOUND_SOUND_SHUTTER_TONE);							
			UIDogSound_Enable(TRUE);
			#else
            UISound_Play(DEMOSOUND_SOUND_SHUTTER_TONE);
			#endif
        }
        break;

    case NVTEVT_KEY_LONG_PRESS:
        bMenuKeyPressed = FALSE;
        break;
    }
#endif
    return NVTEVT_CONSUME;
}

