INT32 UIFlowWndWiFiMovie_OnCustom1(VControl *pCtrl, UINT32 paramNum, UINT32 *paramArray)
{
    UINT32 status = WiFiCmd_GetStatus();
	//printf("call UIFlowWndWiFiMovie_OnCustom1\r\n");

    if (System_GetState(SYS_STATE_CURRMODE) != PRIMARY_MODE_MOVIE) {
        return NVTEVT_CONSUME;
    }

	if ((SysGetFlag(FL_GSENSOR) != GSENSOR_OFF) || (isACCTrigParkMode) ||(BT_EVENT)) {
        if (status == WIFI_MOV_ST_RECORD) {
            FlowMovie_WakeUpLCDBacklight();
#ifdef AUTO_EVENT_DET_FUNC
            if ((isACCTrigParkMode) && (isACCTrigPreRecordDet)) {
                if ((FlowMovie_GetSOSStatusNow() == FALSE) && (ParkingM_PreRecord_EMR == FALSE)) {
                    ImageApp_MovieMulti_TrigEMR(_CFG_REC_ID_1);
                    ParkingM_PreRecord_EMR = TRUE;
                    #if 1//(defined(_NVT_ETHREARCAM_RX_))
                    if(FlowMovie_IsEthCamConnectOK()){
                        ImageApp_MovieMulti_TrigEMR(_CFG_ETHCAM_ID_1);
                    }
                    #endif
                    FlowWiFiMovie_IconDrawSOS(TRUE);
                    //UxCtrl_SetShow(&UIFlowWndWiFiMovie_Static_SOS_BigCtrl, TRUE);
                    FlowMovie_SetSOSStatusNow(TRUE);
                }
                return NVTEVT_CONSUME;
            }
#endif
			//if (SysGetFlag(FL_MOVIE_URGENT_PROTECT_AUTO) == MOVIE_URGENT_PROTECT_AUTO_ON)
            {
				FlowMovie_SetCrash();
                if (FlowMovie_GetSOSStatusNow() == FALSE) {					
					Ux_SendEvent(&CustomMovieObjCtrl, NVTEVT_EXE_MOVIE_REC_RAWENC, 0);				
                    FlowWiFiMovie_IconDrawSOS(TRUE);
                    //UxCtrl_SetShow(&UIFlowWndWiFiMovie_Static_SOS_BigCtrl, TRUE);
                    FlowMovie_SetSOSStatusNow(TRUE);
                }
			}
        }
    }
    BT_EVENT  = FALSE;
    return NVTEVT_CONSUME;
}

INT32 UIFlowWndWiFiMovie_OnCustom2(VControl *pCtrl, UINT32 paramNum, UINT32 *paramArray)
{
#if 1//(defined(_NVT_ETHREARCAM_RX_))
    //UINT32  WiFiModeBeepCount = 0;
	//printf("call UIFlowWndWiFiMovie_OnCustom2\r\n");
   //notify app disconnect
    WifiApp_SendCmd(WIFIAPP_CMD_NOTIFY_STATUS, WIFIAPP_RET_DISCONNECT);
    if (FlowMovie_WakeUpLCDBacklight()) {
        //return NVTEVT_CONSUME;
    }

    if (0/*UxCtrl_IsShow(&UIFlowWndWiFiMovie_Static_SOS_BigCtrl)*/) {
        return NVTEVT_CONSUME;
    }
//test wifi need shield
#if (ASR_FUNCTION == ENABLE)
	// close ASR
	if (SysGetFlag(FL_ASR) == ASR_STANDARD) {
		//printf("call ASR_STANDARD \r\n",SysGetFlag(FL_ASR) );
		ASR_Uninstall();
	}
	ASR_GetPCMData_EN = FALSE;   
#endif
    if (WiFiCmd_GetStatus() == WIFI_MOV_ST_RECORD) {
        if (FlowWiFiMovie_GetRecCurrTime() <= 1) {
            Delay_DelayMs(1000);
        }
        FlowWiFiMovie_StopRec();
        Delay_DelayMs(300);
    }
    UIFlowWndWiFiMovie_UpdateWiFiData(FALSE);
	#if PLAY_SOUND_IN_OTHER_TASK
	UIDogSound_Enable(FALSE);
	DogSoundPlayID(UIVoice_GetIndex(DEMOSOUND_SOUND_WIFIDISABLE_TONE));							
	UIDogSound_Enable(TRUE);
	#else
	UIVoice_Play(DEMOSOUND_SOUND_WIFIDISABLE_TONE);
	#endif
    Delay_DelayMs(100);	
    FlowWiFiMovie_IconDrawWiFiDisConnected(TRUE);
    Control_LedTurn(WIFI_LED,0);
    //GxLED_SetCtrl(KEYSCAN_LED_FCS, TURNON_LED, FALSE);
    KeyScan_EnableMisc(TRUE);
    UI_SetData(FL_MOVIE_CODEC, g_uiPreMovieCodec);

#if (WIFI_FUNC == ENABLE)
#if 0//!defined(_NVT_SDIO_WIFI_NONE_) || !defined(_NVT_USB_WIFI_NONE_)
        //notify current connected socket,new connect not get IP and socket not create
        //cannot disconnet immediate,suggest after 500 ms
        WifiApp_SendCmd(WIFIAPP_CMD_NOTIFY_STATUS, WIFIAPP_RET_DISCONNECT);
        //delay 500 ms,and then close window
        //in window,use GxTimer replace Timer Delay,it would occupat UI task
        GxTimer_StartTimer(TIMER_HALF_SEC, NVTEVT_DELAY_CLOSE_TIMER, ONE_SHOT);
#else
        bWndWiFiMovieOpenFirst = FALSE;
        if (System_GetState(SYS_STATE_CURRMODE) == PRIMARY_MODE_MOVIE) {
            Ux_PostEvent(NVTEVT_SYSTEM_MODE, 2, System_GetState(SYS_STATE_CURRMODE),SYS_SUBMODE_NORMAL);
        } else {
            UI_SetData(FL_PreMode, UI_GetData(FL_ModeIndex));
            UI_SetData(FL_NextMode, PRIMARY_MODE_MOVIE);
            Ux_PostEvent(NVTEVT_SYSTEM_MODE, 2, PRIMARY_MODE_MOVIE, SYS_SUBMODE_NORMAL);
        }
        //should close network application,then stop wifi
        Ux_PostEvent(NVTEVT_EXE_WIFI_STOP, 0);
        //SysSetFlag(FL_WIFI, WIFI_OFF);
#endif
#endif
#endif
    return NVTEVT_CONSUME;
}

INT32 UIFlowWndWiFiMovie_OnKeyRcShutter2(VControl *pCtrl, UINT32 paramNum, UINT32 *paramArray)
{
#if 1//(defined(_NVT_ETHREARCAM_RX_))
	//printf("call UIFlowWndWiFiMovie_OnKeyRcShutter2\r\n");
    UINT32  uiKeyAct;
    UINT32  status = WiFiCmd_GetStatus();

    uiKeyAct = paramArray[0];

    switch (uiKeyAct) {
    case NVTEVT_KEY_PRESS:

        //UISound_Play(DEMOSOUND_SOUND_KEY_TONE);

        switch (status) {
        case WIFI_MOV_ST_IDLE:
        case WIFI_MOV_ST_LVIEW:
            if (FlowMovie_WakeUpLCDBacklight()) {
                //return NVTEVT_CONSUME;
            }

            if (System_GetState(SYS_STATE_CARD) == CARD_REMOVED) {
				#if PLAY_SOUND_IN_OTHER_TASK
				UIDogSound_Enable(FALSE);
				DogSoundPlayID(UIVoice_GetIndex(DEMOSOUND_SOUND_PINSERTCARD_TONE));							
				UIDogSound_Enable(TRUE);
				#else
				UIVoice_Play(DEMOSOUND_SOUND_PINSERTCARD_TONE);
				#endif
		        Delay_DelayMs(100);
                Ux_OpenWindow(&UIFlowWndWrnMsgCtrl, 2, UIFlowWndWrnMsg_StatusTXT_Msg_STRID_PLEASE_INSERT_SD, FLOWWRNMSG_TIMER_2SEC);
                return NVTEVT_CONSUME;
            }
            break;

        case WIFI_MOV_ST_RECORD:
            //if parking mode, not turn on LCD backlight
            if (!isACCTrigParkMode) {
                FlowMovie_WakeUpLCDBacklight();
            }
#ifdef AUTO_EVENT_DET_FUNC
            if ((isACCTrigParkMode) && (isACCTrigPreRecordDet)) {
                if ((FlowMovie_GetSOSStatusNow() == FALSE) && (ParkingM_PreRecord_EMR == FALSE)) {
                    ImageApp_MovieMulti_TrigEMR(_CFG_REC_ID_1);
                    ParkingM_PreRecord_EMR = TRUE;
                    if(FlowMovie_IsEthCamConnectOK()){
                        ImageApp_MovieMulti_TrigEMR(_CFG_ETHCAM_ID_1);
                    }
                    FlowWiFiMovie_IconDrawSOS(TRUE);
                    //UxCtrl_SetShow(&UIFlowWndWiFiMovie_Static_SOS_BigCtrl, TRUE);
                    FlowMovie_SetSOSStatusNow(TRUE);
                    WiFiManualSetSOS = TRUE;
                }
                return NVTEVT_CONSUME;
            }
#endif
            //if (SysGetFlag(FL_MOVIE_URGENT_PROTECT_AUTO) == MOVIE_URGENT_PROTECT_AUTO_ON)
            {
				FlowMovie_SetCrash();
                if (FlowMovie_GetSOSStatusNow() == FALSE) {
                    FlowWiFiMovie_IconDrawSOS(TRUE);
                    //UxCtrl_SetShow(&UIFlowWndWiFiMovie_Static_SOS_BigCtrl, TRUE);
                    FlowMovie_SetSOSStatusNow(TRUE);
                    WiFiManualSetSOS = TRUE;

                    //photo capture
                    FlowWiFiMovie_DrawPIM(TRUE);
                    Ux_SendEvent(&CustomMovieObjCtrl, NVTEVT_EXE_MOVIE_REC_RAWENC, 0);
					#if PLAY_SOUND_IN_OTHER_TASK
	                UIDogSound_Enable(FALSE);
			        DogSoundPlayID(DEMOSOUND_SOUND_SHUTTER_TONE);							
					UIDogSound_Enable(TRUE);
					#else
                    UISound_Play(DEMOSOUND_SOUND_SHUTTER_TONE);
					#endif
                }
            }
            break;
        }
        break;
    }
#endif
    return NVTEVT_CONSUME;
}

INT32 UIFlowWndWiFiMovie_OnEdogAlarm(VControl *pCtrl, UINT32 paramNum, UINT32 *paramArray)
{
	//debug_msg("***********UIFlowWndWiFiMovie_OnEdogAlarm TypePre=0x%x TypeNow0x%x\r\n",paramArray[0],paramArray[1]);
#if defined(_GPS_EDOG_)
    if(!g_bManualCloseEdogWnd)
    {
        if(SysGetFlag(FL_EDOG_OVERSPEED_ALARM) == EDOG_OVERSPEED_ALARM_ON)
        {
            if(SysGetFlag(FL_EDOG_MODE) == EDOG_MODE_OVERSPEED)
            {
                if(EdogInfo_Alarm.Alarm_Type > 0x0C)
                {
                    return NVTEVT_CONSUME;
                }
            }
            FlowMovie_WakeUpLCDBacklight();
            //Show Edog Alarm UI & Play Voice
            Ux_OpenWindow(&UIFlowWndEdogMsgCtrl, 0);
            Ux_Redraw();
            if(EdogInfo_Alarm.Alarm_YN == 0x01)
			{
            	FlowMovie_EdogAlarmVoice();
			}
        }
    }
#elif defined(_GPS_EDOG_UNIQUE_SKY_)
	if(SysGetFlag(FL_EDOG_OVERSPEED_ALARM) == EDOG_OVERSPEED_ALARM_ON)
	{
		if (WiFiCmd_GetStatus() != WIFI_MOV_ST_RECORD) 
		{
			return NVTEVT_CONSUME;
		}

		if(!g_bManualCloseEdogWnd)
		{
			UINT8 type = paramArray[1];
			if(FlowMovie_isEdogTypeValid(type))
			{
				FlowMovie_WakeUpLCDBacklight();
				//Show Edog Alarm UI & Play Voice
				if(((type>=0x40)&&(type<=0x4F))||(type==0xC4))
				{
					Ux_OpenWindow(&UIFlowWndEdogMsg_UniqueSkyCtrl, 1,type);
				}
				else
				{

					Ux_OpenWindow(&UIFlowWndEdogMsgCtrl,1,type);
				}
				Ux_Redraw();
				FlowMovie_EdogAlarmVoice(type);
			}
			else
			{
					if((GPSRadar_GetCASNesting()!=0)
						&&(GPSRadar_GetCurrentCASStart()==SPEED_DECTION_START))
				{
					FlowMovie_WakeUpLCDBacklight();
					Ux_OpenWindow(&UIFlowWndEdogMsg_UniqueSkyCtrl, 0);
					Ux_Redraw();
				}
			}
		}
	}
#endif
	return NVTEVT_CONSUME;
}
void UIFlowWndWiFiMovie_StopTimer(void)
{
	 if (gUIFlowWndWiFiMotionDetTimerID != NULL_TIMER)
    {
        GxTimer_StopTimer(&gUIFlowWndWiFiMotionDetTimerID);
    }
    if (g_uiDateTimerID != NULL_TIMER)
    {
        GxTimer_StopTimer(&g_uiDateTimerID);
    }
	if (g_uiBeepTimerID != NULL_TIMER)
    {
        GxTimer_StopTimer(&g_uiBeepTimerID);
    }
}
void UIFlowWndWiFiMovie_StartTimer(void)
{
	if (gUIFlowWndWiFiMotionDetTimerID == NULL_TIMER)
   {
	   gUIFlowWndWiFiMotionDetTimerID = GxTimer_StartTimer(TIMER_HALF_SEC, NVTEVT_05SEC_TIMER, CONTINUE);
   }
   if (g_uiDateTimerID == NULL_TIMER)
   {
	   g_uiDateTimerID = GxTimer_StartTimer(TIMER_ONE_SEC, NVTEVT_1SEC_TIMER, CONTINUE);
   }
   if (g_uiBeepTimerID == NULL_TIMER) {
	   g_uiBeepTimerID = GxTimer_StartTimer(100, NVTEVT_01SEC_TIMER, CONTINUE);
   }

}
